import{_ as e,o as r,c as p,ah as i}from"./chunks/framework.BNo2o5Ln.js";const u=JSON.parse('{"title":"API 网关","description":"","frontmatter":{"title":"API 网关","order":3},"headers":[],"relativePath":"server/distribute/micro/gateway/index.md","filePath":"server/distribute/micro/gateway/index.md"}'),t={name:"server/distribute/micro/gateway/index.md"};function l(n,a,d,o,h,s){return r(),p("div",null,[...a[0]||(a[0]=[i('<h1 id="api-网关" tabindex="-1">API 网关 <a class="header-anchor" href="#api-网关" aria-label="Permalink to “API 网关”">​</a></h1><p>API 网关是微服务架构的统一入口，处理所有外部请求，负责路由转发、协议转换、认证授权、限流熔断等横切关注点。API 网关简化了客户端的调用，将服务治理逻辑从服务中剥离。</p><h2 id="为什么需要-api-网关" tabindex="-1">为什么需要 API 网关 <a class="header-anchor" href="#为什么需要-api-网关" aria-label="Permalink to “为什么需要 API 网关”">​</a></h2><p>客户端复杂：微服务架构下，客户端需要调用多个服务，需要处理服务发现、负载均衡、熔断降级，客户端复杂度高。</p><p>跨域问题：浏览器的同源策略限制跨域请求，需要服务支持 CORS。</p><p>认证授权：每个服务都需要认证授权，代码重复，难以维护。</p><p>限流熔断：每个服务都需要限流熔断，实现复杂。</p><p>API 网关的优势：统一入口（所有请求通过网关）、协议转换（HTTP 转 gRPC、WebSocket 等）、认证授权（集中管理认证授权）、限流熔断（集中管理限流熔断）、监控日志（集中记录访问日志）。</p><h2 id="api-网关的核心功能" tabindex="-1">API 网关的核心功能 <a class="header-anchor" href="#api-网关的核心功能" aria-label="Permalink to “API 网关的核心功能”">​</a></h2><p>路由转发：根据请求路径、头部、查询参数将请求转发到不同的后端服务。</p><p>负载均衡：在多个服务实例间分配请求，支持轮询、随机、权重、最少连接等策略。</p><p>协议转换：HTTP 转 gRPC、HTTP 转 WebSocket、HTTP 转 Dubbo 等。</p><p>认证授权：统一处理认证授权，支持 JWT、OAuth2、API Key 等。</p><p>限流熔断：保护后端服务不被过载请求打垮，支持令牌桶、漏桶、固定窗口等算法。</p><p>请求响应增强：添加或修改请求头、响应头，聚合多个服务的响应。</p><p>缓存：缓存后端服务的响应，减轻后端压力。</p><p>监控日志：记录访问日志，监控请求量、延迟、错误率。</p><p>灰度发布：根据请求特征路由到不同版本的服务，实现灰度发布。</p><h2 id="主流-api-网关" tabindex="-1">主流 API 网关 <a class="header-anchor" href="#主流-api-网关" aria-label="Permalink to “主流 API 网关”">​</a></h2><h3 id="zuul-1-x" tabindex="-1">Zuul 1.x <a class="header-anchor" href="#zuul-1-x" aria-label="Permalink to “Zuul 1.x”">​</a></h3><p>Zuul 1.x 是 Netflix 开源的 API 网关，基于 Servlet 阻塞 I/O。</p><p>Zuul 的核心：Zuul Servlet（处理所有请求）、Filter（过滤器链）、Loader（动态加载 Filter）。</p><p>Zuul Filter：Pre Filter（路由前处理）、Routing Filter（路由转发）、Post Filter（响应后处理）、Error Filter（错误处理）。</p><p>Zuul 1.x 的问题：阻塞 I/O、性能差、不支持长连接。</p><h3 id="zuul-2-x" tabindex="-1">Zuul 2.x <a class="header-anchor" href="#zuul-2-x" aria-label="Permalink to “Zuul 2.x”">​</a></h3><p>Zuul 2.x 是 Netflix 开源的下一代 API 网关，基于 Netty 非阻塞 I/O。</p><p>Zuul 2.x 的特性：非阻塞 I/O、高性能、支持长连接、异步过滤器。</p><p>Zuul 2.x 的问题：与 1.x 不兼容、学习曲线陡峭、维护状态不佳。</p><h3 id="spring-cloud-gateway" tabindex="-1">Spring Cloud Gateway <a class="header-anchor" href="#spring-cloud-gateway" aria-label="Permalink to “Spring Cloud Gateway”">​</a></h3><p>Spring Cloud Gateway 是 Spring Cloud 的 API 网关，基于 WebFlux 非阻塞 I/O。</p><p>Spring Cloud Gateway 的核心：Route（路由规则）、Predicate（匹配条件）、Filter（过滤器）。</p><p>Spring Cloud Gateway 的特性：非阻塞 I/O、与 Spring 生态集成、动态路由、限流（基于 Redis）。</p><p>Spring Cloud Gateway 的问题：功能相对简单、不支持 Dubbo 路由。</p><h3 id="kong" tabindex="-1">Kong <a class="header-anchor" href="#kong" aria-label="Permalink to “Kong”">​</a></h3><p>Kong 是 Mashape 开源的 API 网关，基于 OpenResty（Nginx + Lua）。</p><p>Kong 的架构：Nginx（处理请求）、Lua（业务逻辑）、Cassandra（数据存储）。</p><p>Kong 的特性：高性能（基于 Nginx）、插件丰富（认证、限流、日志等）、可扩展（支持自定义插件）。</p><p>Kong 的优势：性能高、功能完善、生态活跃。</p><p>Kong 的问题：依赖 Cassandra、部署复杂、配置复杂。</p><h3 id="apisix" tabindex="-1">APISIX <a class="header-anchor" href="#apisix" aria-label="Permalink to “APISIX”">​</a></h3><p>APISIX 是 Apache 开源的 API 网关，基于 OpenResty 和 etcd。</p><p>APISIX 的架构：Nginx（处理请求）、Lua（业务逻辑）、etcd（配置存储）。</p><p>APISIX 的特性：高性能（基于 Nginx）、动态配置（基于 etcd）、插件丰富、云原生（Kubernetes Ingress）。</p><p>APISIX 的优势：性能高、配置简单、与 Kubernetes 集成、中文文档完善。</p><p>APISIX 的问题：社区相对年轻、不如 Kong 成熟。</p><h3 id="traefik" tabindex="-1">Traefik <a class="header-anchor" href="#traefik" aria-label="Permalink to “Traefik”">​</a></h3><p>Traefik 是云原生的 API 网关，自动发现服务。</p><p>Traefik 的特性：自动发现服务（Kubernetes、Consul、Etcd 等）、配置简单（基于 YAML）、自动 HTTPS（Let&#39;s Encrypt）、Metrics（Prometheus、StatsD）。</p><p>Traefik 的优势：云原生、配置简单、自动服务发现。</p><p>Traefik 的问题：性能不如 Nginx、功能相对简单。</p><h2 id="api-网关的设计模式" tabindex="-1">API 网关的设计模式 <a class="header-anchor" href="#api-网关的设计模式" aria-label="Permalink to “API 网关的设计模式”">​</a></h2><h3 id="后端服务对于前端-bff" tabindex="-1">后端服务对于前端（BFF） <a class="header-anchor" href="#后端服务对于前端-bff" aria-label="Permalink to “后端服务对于前端（BFF）”">​</a></h3><p>后端服务对于前端（Backend For Frontend）是为不同客户端（Web、移动端）提供不同的 API 网关。BFF 根据客户端的需求聚合后端服务的响应，提供定制化的 API。</p><p>BFF 的优势：减少客户端复杂度、优化网络请求（一次请求聚合多个服务）、隔离不同客户端的需求。</p><p>BFF 的问题：API 数量增加、维护成本增加。</p><h3 id="网关集群" tabindex="-1">网关集群 <a class="header-anchor" href="#网关集群" aria-label="Permalink to “网关集群”">​</a></h3><p>API 网关必须集群部署，避免单点故障。网关前可以部署负载均衡器（如 Nginx、ALB），将请求分发到网关实例。</p><p>网关需要保持无状态，便于水平扩展。状态（如限流计数）可以存储在 Redis 中。</p><h3 id="网关的高可用" tabindex="-1">网关的高可用 <a class="header-anchor" href="#网关的高可用" aria-label="Permalink to “网关的高可用”">​</a></h3><p>网关集群部署、健康检查、故障自动剔除、自动扩缩容。</p><p>网关前部署负载均衡器，实现高可用和负载均衡。</p><p>网关需要快速失败，避免阻塞请求。设置超时时间、熔断器。</p><h2 id="api-网关的最佳实践" tabindex="-1">API 网关的最佳实践 <a class="header-anchor" href="#api-网关的最佳实践" aria-label="Permalink to “API 网关的最佳实践”">​</a></h2><p>路由规则：使用简洁的路由规则，避免过于复杂的正则表达式。</p><p>限流保护：保护网关和后端服务，避免被过载请求打垮。根据接口的重要性设置不同的限流策略。</p><p>超时配置：设置合理的超时时间，避免长时间等待。超时时间应大于后端服务的超时时间。</p><p>熔断降级：后端服务故障时快速失败，返回默认值或错误响应，避免雪崩。</p><p>日志记录：记录访问日志，包括请求时间、响应时间、错误码，便于问题排查。</p><p>监控告警：监控网关的请求量、延迟、错误率，异常时及时告警。</p><p>灰度发布：根据请求特征路由到不同版本的服务，实现灰度发布。可以根据 IP、Header、Cookie 等路由。</p><p>API 网关是微服务架构的入口，理解网关的原理和权衡，有助于设计合适的网关方案。</p>',71)])])}const c=e(t,[["render",l]]);export{u as __pageData,c as default};
